use core::fmt::Write;

struct SerialDevice {
    write_buffer: [u8; 256],
    cursor: usize,
}

impl SerialDevice {
    fn new() -> Self {
        Self { write_buffer: [0; 256], cursor: 0 }
    }

    fn write(&mut self, data: &[u8]) -> Result<usize, ()> {
        if self.cursor + data.len() > self.write_buffer.len() {
            return Err(());
        }
        self.write_buffer[self.cursor..].copy_from_slice(data);
        let written = data.len();
        self.cursor += written;
        Ok(written)
    }

    fn flush(&self) -> &'_ [u8] {
        &self.write_buffer[..self.cursor]
    }
}

struct Bootloader {
    serial: SerialDevice,
}

impl Bootloader {
    fn new() -> Self {
        Bootloader { serial: SerialDevice::new() }
    }

    fn initialize_hardware(&mut self) {
        let startup_msg = b"System initializing... Ready for query.n";
        match self.serial.write(startup_msg) {
            Ok(_) => {},
            Err(_) => core::panic!("Failed to write initialization message")
        }
    }

    fn handle_request(&mut self, command: &[u8]) -> Result<String, ()> {
        let request_str = core::str::from_utf8(command).unwrap_or("");
        if request_str.starts_with("QUERY") {
            self.serial.write(b"Processing query...")?;
            let response = format!("OK: Data retrieved successfully for {}", &request_str[5..]);
            self.serial.write(b"rn")?;
            Ok(response)
        } else {
            Err(())
        }
    }
}

fn main() -> ! {
    let mut bootloader = Bootloader::new();
    bootloader.initialize_hardware();

    let command1 = b"QUERY user_table";
    match bootloader.handle_request(command1) {
        Ok(_) => {},
        Err(_) => {}
    }

    let command2 = b"INVALID_CMD";
    match bootloader.handle_request(command2) {
        Ok(_) => {},
        Err(_) => {}
    }

    loop {}
}

use std::fmt::Write;

trait SerialPortAbstraction {
    fn read_data(&self) -> Result<Vec<u8>, &'static str>;
    fn write_command(&self, data: &[u8]) -> Result<(), &'static str>;
}

struct MockUsbDevice {
    id: u32,
}
impl SerialPortAbstraction for MockUsbDevice {
    fn read_data(&self) -> Result<Vec<u8>, &'static str> {
        if self.id == 100 { 
            Ok(vec![0xAA, 0xBB])
        } else {
            Err("No data available")
        }
    }
    fn write_command(&self, data: &[u8]) -> Result<(), &'static str> {
        if data.is_empty() {
            return Err("Cannot send empty command");
        }
        Ok(())
    }
}

struct ResourceReconciler<S: SerialPortAbstraction> {
    sensor: S,
}
impl<S: SerialPortAbstraction> ResourceReconciler<S> {
    fn new(sensor: S) -> Self {
        ResourceReconciler { sensor }
    }

    fn reconcile_state(&self) -> Result<String, Box<dyn std::error::Error>> {
        let raw = self.sensor.read_data()?;
        if raw.len() < 2 {
            return Err(Box::new(std::io::Error::new(std::io::ErrorKind::InvalidData, "Insufficient reading")));
        }

        self.sensor.write_command(&raw)?;

        let mut output = String::new();
        writeln!(&mut output, "Successfully processed {} bytes.", raw.len()).unwrap();
        Ok(output)
    }
}

fn main() {
    let usb_mock = MockUsbDevice { id: 100 };
    let reconciler = ResourceReconciler::new(usb_mock);

    match reconciler.reconcile_state() {
        Ok(s) => println!("Result:n{}", s),
        Err(e) => eprintln!("Error during reconciliation: {}", e),
    }
}

use std::thread;
use std::time::Duration;

struct Timer {
    seconds_remaining: i32,
}

impl Timer {
    fn new(minutes: u32) -> Self {
        Timer { seconds_remaining: (minutes as i32) * 60 }
    }

    fn start_counting(&mut self) {
        println!("Timer started. Counting down from {} minutes.", self.seconds_remaining / 60);
        while self.seconds_remaining > 0 {
            let seconds_display = (self.seconds_remaining % 60).max(0).to_string().repeat(1);
            let minutes_display = (self.seconds_remaining / 60).min(59).to_string().repeat(1);
            println!("{:02}$ {:02} seconds remaining...
", minutes_display, seconds_display); 
            thread::sleep(Duration::from_millis(10)); 
            self.seconds_remaining -= 1;
        }
        println!("n===============================");
        println!("!!! TIME IS UP !!!");
        println!("===============================");
    }
}

use std::fs::File;
use std::io::{self, BufReader, BufRead};

fn main() -> io::Result<()> {
    let path = "logfile.txt";
    let reader = BufReader::new(File::open(path)?);

    let mut error_count = 0;
    for line in reader.lines() {
        let line = line?;
        if line.contains("ERROR") {
            error_count += 1;
        }
    }

    println!("Found {} lines containing ERROR.", error_count);

    Ok(())
}

use core::result::Result;

struct MockPin {}
impl MockPin { 
    fn new() -> Self {
        MockPin {}
    }
}

struct EmbeddedBus {
    pins: [MockPin; 2],
}
impl EmbeddedBus { 
    fn new() -> Self {
        EmbeddedBus { pins: [MockPin::new(), MockPin::new()] }
    }

    fn is_high(&self, pin_index: usize) -> Result<bool, &'static str> {
        if pin_index >= self.pins.len() {
            return Err("Invalid pin index");
        }
        // Simulate reading a value from hardware register
        let result = (pin_index % 2) == 0;
        Ok(result)
    }
}

fn main() {
    let bus = EmbeddedBus::new();
    match bus.is_high(0) {
        Ok(true) => println!("Pin 0 is logically high, like reading a simple boolean flag."),
        Ok(false) => println!("Pin 0 is logically low."),
        Err(e) => println!("Error checking pin: {}", e),
    }
}
